package com.yottastudios.ns.collabspace.workspace.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeException;
import com.yottastudios.ns.collabspace.workspace.mapper.SpaceNodeMapper;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;

import java.io.Serializable;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Service
public class SpaceNodeServiceImpl extends ServiceImpl<SpaceNodeMapper, SpaceNodeEntity> implements ISpaceNodeService {
    @Override
    public List<SpaceNodeEntity> listBySpaceId(String spaceId) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getSpaceId, spaceId);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceNodeEntity> listBySpaceId(String spaceId, Boolean isSnapshot) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getSpaceId, spaceId)
                .eq(SpaceNodeEntity::getIsSnapshot, isSnapshot);
        return list(queryWrapper);
    }

    @Override
    public void checkSpaceNodeExist(Long spaceNodeId) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getId, spaceNodeId);
        boolean exists = this.exists(queryWrapper);
        ExceptionUtil.isTrue(exists, SpaceNodeException.NOT_EXIST);
    }

    @Override
    public void recoverNode(long id){
        baseMapper.recoverNode(id);
    }

    @Override
    public SpaceNodeEntity getByIdAllStatus(long id){
        return baseMapper.getByIdAllStatus(id);
    }

    @Override
    public List<SpaceNodeEntity> listByAppSpaceNodeIds(Collection<String> appSpaceNodeIds) {
        if (appSpaceNodeIds == null || appSpaceNodeIds.isEmpty()) {
            return new ArrayList<>();
        }
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().in(SpaceNodeEntity::getAppSpaceNodeId, appSpaceNodeIds);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceNodeEntity> listByIdsIncludeDeleted(Collection<? extends Serializable> ids) {
        if (CollectionUtils.isEmpty(ids)) {
            return new ArrayList<>();
        }
        return baseMapper.listByIdsIncludeDeleted(ids);
    }

    @Override
    public List<SpaceNodeEntity> listLikeName(String name) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getIsDeleted , 0).like(SpaceNodeEntity::getName, name);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceNodeEntity> listByCreators(List<Long> userIds) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getIsDeleted , 0).in(SpaceNodeEntity::getCreatedBy, userIds);
        return list(queryWrapper);
    }

    @Override
    public List<SpaceNodeEntity> getSpaceNodeByAppIds(List<String> appSpaceNodeIds) {
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda().eq(SpaceNodeEntity::getIsDeleted , 0).in(SpaceNodeEntity::getAppSpaceNodeId , appSpaceNodeIds);
        return list(queryWrapper);
    }

    @Override
    public Map<Long, String> getSnapshotNodeIdToSpaceIdMap(Collection<? extends Serializable> nodeIds) {
        if (CollectionUtils.isEmpty(nodeIds)) {
            return new HashMap<>();
        }
        QueryWrapper<SpaceNodeEntity> queryWrapper = new QueryWrapper<>();
        queryWrapper.lambda()
                .select(SpaceNodeEntity::getId, SpaceNodeEntity::getSpaceId)
                .in(SpaceNodeEntity::getId, nodeIds)
                .eq(SpaceNodeEntity::getIsSnapshot, 1);
        return list(queryWrapper).stream()
                .collect(Collectors.toMap(SpaceNodeEntity::getId, SpaceNodeEntity::getSpaceId));
    }

}

