    96→    // ========== submitRequest ==========
    97→
    98→    @Override
    99→    @Transactional(rollbackFor = Exception.class)
   100→    public PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro) {
   101→        Long applicantUserId = SessionContext.getUserId();
   102→        ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);
   103→        ExceptionUtil.isNotNull(documentId, PermissionRequestException.NODE_NOT_EXIST);
   104→
   105→        // 1. Check node exists and get spaceId; resolve numeric pk to appSpaceNodeId
   106→        SpaceNodeEntity spaceNode = getSpaceNodeByNodeId(documentId);
   107→        String resolvedDocumentId = spaceNode.getAppSpaceNodeId();
   108→        String spaceId = spaceNode.getSpaceId();
   109→        String documentName = spaceNode.getName();
   110→
   111→        // 2. Check user is in space
   112→        boolean isInSpace = spaceQueryManager.isUserInSpace(applicantUserId, spaceId);
   113→        ExceptionUtil.isTrue(isInSpace, PermissionRequestException.MEMBER_NOT_IN_SPACE);
   114→
   115→        // 3. Check no pending request for same document
   116→        PermissionRequestEntity pending = baseMapper.selectPendingByDocumentAndApplicant(resolvedDocumentId, applicantUserId);
   117→        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
   118→
   119→        // 4. Check user does not already have node permission
   120→        boolean hasPermission = checkUserHasNodePermission(spaceId, applicantUserId, resolvedDocumentId);
   121→        ExceptionUtil.isFalse(hasPermission, PermissionRequestException.ALREADY_HAVE_PERMISSION);
   122→
   123→        // 5. Debounce: short period repeated submissions only processed once
   124→        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + resolvedDocumentId;
   125→        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
   126→        if (Boolean.FALSE.equals(firstSubmit)) {
   127→            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
   128→            throw new BusinessException(PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
   129→        }
   130→
   131→        // 6. Create permission request record
   132→        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
   133→        PermissionRequestEntity entity = PermissionRequestEntity.builder()
   134→            .id(requestId)
   135→            .applicantUserId(applicantUserId)
   136→            .documentId(resolvedDocumentId)
   137→            .spaceId(spaceId)
   138→            .requestedPermissionType(ro.getRequestedPermissionType())
   139→            .status(STATUS_PENDING)
   140→            .isDeleted(0)
   141→            .createdAt(LocalDateTime.now())
   142→            .updatedAt(LocalDateTime.now())
   143→            .build();
   144→
   145→        boolean flag = save(entity);
   146→        if (!flag) {
   147→            log.error("[1822-PermApply] ERROR CREATE insert failed applicantUserId={} documentId={} spaceId={}",
   148→                applicantUserId, resolvedDocumentId, spaceId);
   149→            throw new BusinessException(PermissionRequestException.INSERT_ERROR);
   150→        }
   151→        log.info("[1822-PermApply] CREATE request requestId={} applicantUserId={} documentId={} spaceId={} requestedType={}",
   152→            requestId, applicantUserId, resolvedDocumentId, spaceId, ro.getRequestedPermissionType());
   153→
   154→        // 7. Get space name and applicant nickname
   155→        SpaceEntity space = spaceService.getBySpaceId(spaceId);
   156→        String spaceName = space != null && space.getName() != null ? space.getName() : "";
   157→        String applicantNickName = getApplicantNickName(applicantUserId);
   158→
   159→        // 8. Notify admins & applicant via apitable gRPC (async)
   160→        notifyAdminsAsync(entity, documentName, applicantNickName, spaceName);
   161→        notifyApplicantAsync(entity, documentName, spaceName);
   162→
   163→        return buildVo(entity, documentName, spaceName);
   164→    }
