   166→    private SpaceNodeEntity getSpaceNodeByNodeId(String nodeId) {
   167→        ExceptionUtil.isNotNull(nodeId, PermissionRequestException.NODE_NOT_EXIST);
   168→        // Always try appSpaceNodeId first: OnlyOffice nodes use a numeric fileId as appSpaceNodeId,
   169→        // which must NOT be treated as the collabspace pk.
   170→        List<SpaceNodeEntity> byAppId = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(nodeId));
   171→        if (CollUtil.isNotEmpty(byAppId)) return byAppId.get(0);
   172→        // Fallback: treat as collabspace pk if numeric
   173→        if (nodeId.matches("^\\d+$")) {
   174→            SpaceNodeEntity node = spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
   175→            ExceptionUtil.isNotNull(node, PermissionRequestException.NODE_NOT_EXIST);
   176→            return node;
   177→        }
   178→        ExceptionUtil.isNotNull(null, PermissionRequestException.NODE_NOT_EXIST);
   179→        return null; // unreachable
   180→    }
   181→
   182→    private SpaceNodeEntity getSpaceNodeByNodeIdSafe(String nodeId) {
   183→        if (nodeId == null) return null;
   184→        // Always try by appSpaceNodeId column first (OnlyOffice fileId is numeric but not the pk).
   185→        List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(nodeId));
   186→        if (CollUtil.isNotEmpty(nodes)) return nodes.get(0);
   187→        // Fallback: treat as pk if numeric.
   188→        if (nodeId.matches("^\\d+$")) {
   189→            return spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
   190→        }
   191→        return null;
   192→    }
