   232→    @Async
   233→    public void notifyAdminsAsync(PermissionRequestEntity request, String documentName,
   234→                                   String applicantNickName, String spaceName) {
   235→        try {
   236→            // Space-level admins (owner + workbench manage permission holders)
   237→            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
   238→
   239→            // Document-level MANAGE permission holders (may differ from space admins)
   240→            List<Long> docManagerUserIds = getDocumentManagerUserIds(request.getDocumentId(), request.getSpaceId());
   241→
   242→            // Merge and deduplicate; exclude the applicant (they shouldn't get notified as approver)
   243→            Set<Long> toNotifySet = new LinkedHashSet<>();
   244→            toNotifySet.addAll(adminUserIds);
   245→            toNotifySet.addAll(docManagerUserIds);
   246→            toNotifySet.remove(request.getApplicantUserId());
   247→            List<Long> allNotifyUserIds = new ArrayList<>(toNotifySet);
   248→
   249→            if (CollUtil.isEmpty(allNotifyUserIds)) {
   250→                log.warn("[1822-PermApply] notifyAdmins no recipients spaceId={} documentId={}",
   251→                    request.getSpaceId(), request.getDocumentId());
   252→                return;
   253→            }
   254→            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} spaceAdminCount={} docManagerCount={} totalNotify={}",
   255→                request.getId(), request.getDocumentId(), adminUserIds.size(), docManagerUserIds.size(), allNotifyUserIds.size());
   256→
   257→            Map<String, Object> extras = new HashMap<>();
   258→            extras.put("requestId", request.getId());
   259→            extras.put("spaceName", spaceName);
   260→            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
   261→            extras.put("applicantNickName", applicantNickName);
   262→            extras.put("documentId", request.getDocumentId());
   263→            extras.put("documentName", documentName);
   264→            extras.put("requestedPermissionType", request.getRequestedPermissionType());
   265→            extras.put("documentAuth", mapPermissionTypeToLabel(request.getRequestedPermissionType()));
   266→            extras.put("status", request.getStatus());
   267→
   268→            Map<String, Object> bodyMap = new HashMap<>();
   269→            bodyMap.put(BODY_EXTRAS, extras);
   270→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
   271→
   272→            apitableGrpcClientService.createNotification(
   273→                DOCUMENT_PERMISSION_REQUEST,
   274→                String.valueOf(request.getApplicantUserId()),
   275→                allNotifyUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
   276→                request.getDocumentId(),
   277→                request.getSpaceId(),
   278→                bodyJson,
   279→                true
   280→            );
   281→
   282→            log.info("[1822-PermApply] notifyAdmins done requestId={} totalNotified={}", request.getId(), allNotifyUserIds.size());
   283→        } catch (Exception e) {
   284→            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
   285→        }
   286→    }
