   371→    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
   372→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
   373→
   374→        String approverNickName = getApproverNickName(approverUserId);
   375→
   376→        // Get applicant unitId
   377→        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
   378→                List.of(request.getApplicantUserId()), request.getSpaceId())
   379→            .stream().findFirst().orElse(null);
   380→        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   381→        Long unitId = applicantMember.getUnitId();
   382→        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   383→
   384→        // Map permission type to node role
   385→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
   386→        log.info("[1822-PermApply] APPROVE mapRole requestId={} requestedType={} nodeRole={} unitId={} documentId={}",
   387→            request.getId(), request.getRequestedPermissionType(), nodeRole, unitId, request.getDocumentId());
   388→
   389→        // Add node role
   390→        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
   391→        if (spaceNodeId != null) {
   392→            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
   393→                Collections.singletonList(unitId));
   394→            log.info("[1822-PermApply] APPROVE addNodeRole ok spaceNodeId={} nodeRole={} unitId={}", spaceNodeId, nodeRole, unitId);
   395→        } else {
