   397→                request.getDocumentId());
   398→        }
   399→
   400→        // Update permission request status in collabspace
   401→        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
   402→        log.info("[1822-PermApply] APPROVE DB updateStatus requestId={} status=APPROVED approverUserId={} rows={}",
   403→            request.getId(), approverUserId, rows);
   404→
   405→        // Update notification extras in apitable (via gRPC)
