   408→
   409→        // Mark notification as read in apitable (via gRPC)
   410→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
   411→
   412→        // Notify applicant that their request was approved
   413→        notifyApplicantResultAsync(request, STATUS_APPROVED, approverUserId, approverNickName);
   414→
   415→        log.info("[1822-PermApply] APPROVE done requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
   416→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
   417→    }
