   459→    // ========== Validation Helpers ==========
   460→
   461→    /**
   462→     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
   463→     * Used for reapprove, which can act on already-processed requests.
   464→     */
   465→    private void validateRequestForApprover(String requestId, Long approverUserId) {
   466→        if (requestId == null || requestId.isBlank()) {
   467→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
   468→        }
   469→        PermissionRequestEntity request = baseMapper.selectById(requestId);
   470→        if (request == null) {
   471→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
   472→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
   473→        }
   474→        validateApproverIsAdmin(approverUserId, request.getSpaceId());
   475→    }
   476→
   477→    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
   478→        if (requestId == null || requestId.isBlank()) {
   479→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
   480→        }
   481→        PermissionRequestEntity request = baseMapper.selectById(requestId);
   482→        if (request == null) {
   483→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
   484→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
   485→        }
   486→        if (!STATUS_PENDING.equals(request.getStatus())) {
   487→            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
   488→                request.getId(), request.getStatus());
   489→            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
   490→        }
   491→        validateApproverIsAdmin(approverUserId, request.getSpaceId());
   492→        return request;
   493→    }
   494→
   495→    private void validateApproverIsAdmin(Long approverUserId, String spaceId) {
   496→        boolean isAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
   497→        ExceptionUtil.isTrue(isAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
   498→    }
   499→
   500→    private String getApproverNickName(Long approverUserId) {
   501→        try {
   502→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(approverUserId);
   503→            return user != null && user.getNickName() != null ? user.getNickName() : "";
   504→        } catch (Exception e) {
   505→            return "";
   506→        }
   507→    }
   508→
   509→    private Long parseSpaceNodeId(String documentId) {
   510→        if (documentId == null) return null;
   511→        // Always look up by appSpaceNodeId column first.
   512→        // OnlyOffice nodes (PPT/Excel/Word) use a numeric OnlyOffice fileId as appSpaceNodeId,
   513→        // which must NOT be treated as the collabspace pk.
   514→        Long byAppNodeId = getSpaceNodeIdByAppNodeId(documentId);
   515→        if (byAppNodeId != null) return byAppNodeId;
   516→        // Fallback: if documentId is a pure numeric string, treat as spaceNodeId pk.
   517→        try {
   518→            return Long.parseLong(documentId);
   519→        } catch (NumberFormatException e) {
   520→            return null;
   521→        }
   522→    }
   523→
   524→    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
   525→        try {
   526→            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(appNodeId));
   527→            if (CollUtil.isNotEmpty(nodes)) {
   528→                return nodes.get(0).getId();
   529→            }
   530→        } catch (Exception e) {
   531→            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
   532→        }
   533→        return null;
   534→    }
   535→
   536→    /**
   537→     * Returns the collabspace userIds of all users who have explicit MANAGE permission on the document.
   538→     * Handles both member-type (individual) and team-type (department) unit entries in control_role.
   539→     */
   540→    private List<Long> getDocumentManagerUserIds(String documentId, String spaceId) {
   541→        try {
   542→            Long spaceNodeId = parseSpaceNodeId(documentId);
   543→            if (spaceNodeId == null) return List.of();
   544→
   545→            List<ControlRoleEntity> roles = controlRoleService.getByControlId(spaceNodeId.toString());
   546→            List<Long> managerUnitIds = roles.stream()
   547→                .filter(r -> MANAGER.equals(r.getRoleCode()))
   548→                .map(ControlRoleEntity::getUnitId)
   549→                .toList();
   550→
   551→            if (CollUtil.isEmpty(managerUnitIds)) return List.of();
   552→
   553→            List<NodeRoleUnit> nodeRoleUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, managerUnitIds);
   554→
   555→            Set<Long> userIds = new HashSet<>();
   556→            List<Long> memberTypeRefIds = new ArrayList<>(); // memberId for unitType=3
   557→
   558→            for (NodeRoleUnit unit : nodeRoleUnits) {
   559→                if (unit.getUnitRefId() == null) continue;
   560→                Integer unitType = unit.getUnitType();
   561→                if (unitType != null && unitType == 1) {
   562→                    // Team/department: expand to all members
   563→                    List<UserSimpleInfoVo> members = apitableGrpcClientService.selectMembersByTeamId(spaceId, unit.getUnitRefId());
   564→                    members.stream().filter(m -> m.getId() != null).forEach(m -> userIds.add(m.getId()));
   565→                } else if (unitType != null && unitType == 3) {
   566→                    // Individual member: collect memberId for batch email lookup
   567→                    memberTypeRefIds.add(unit.getUnitRefId());
   568→                }
   569→            }
   570→
   571→            // Resolve member-type units: memberId → email → userId
   572→            if (!memberTypeRefIds.isEmpty()) {
   573→                IPage<SpaceMemberVo> memberPage = apitableGrpcClientService.getSpaceMembers(spaceId, 1, 999);
   574→                Map<String, String> memberIdToEmail = memberPage.getRecords().stream()
   575→                    .filter(m -> m.getMemberId() != null && m.getEmail() != null)
   576→                    .collect(Collectors.toMap(SpaceMemberVo::getMemberId, SpaceMemberVo::getEmail, (a, b) -> a));
   577→
   578→                List<String> emails = memberTypeRefIds.stream()
   579→                    .map(refId -> memberIdToEmail.get(String.valueOf(refId)))
   580→                    .filter(Objects::nonNull)
   581→                    .toList();
   582→
   583→                if (!emails.isEmpty()) {
   584→                    apitableGrpcClientService.getUserByEmails(emails).stream()
   585→                        .filter(u -> u.getId() != null)
   586→                        .forEach(u -> userIds.add(u.getId()));
   587→                }
   588→            }
   589→
   590→            log.info("[1822-PermApply] getDocumentManagerUserIds documentId={} managerUnitCount={} resolvedUserCount={}",
   591→                documentId, managerUnitIds.size(), userIds.size());
   592→            return new ArrayList<>(userIds);
   593→        } catch (Exception e) {
   594→            log.warn("[1822-PermApply] getDocumentManagerUserIds failed documentId={} error={}", documentId, e.getMessage());
   595→            return List.of();
   596→        }
   597→    }
   598→
   599→    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
   600→        return switch (requestedPermissionType) {
   601→            case "READ" -> READER;
   602→            case "EDIT" -> EDITOR;
   603→            case "MANAGE" -> MANAGER;
   604→            default -> READER;
   605→        };
   606→    }
   607→
   608→    private String mapPermissionTypeToLabel(String requestedPermissionType) {
   609→        if (requestedPermissionType == null) return "";
   610→        return switch (requestedPermissionType) {
   611→            case "READ" -> "查看";
   612→            case "EDIT" -> "编辑";
   613→            case "MANAGE" -> "管理";
   614→            default -> requestedPermissionType;
   615→        };
   616→    }
   617→
   618→    @Async
   619→    public void notifyApplicantResultAsync(PermissionRequestEntity request, String status,
   620→                                            Long approverUserId, String approverNickName) {
   621→        try {
   622→            String templateId = STATUS_APPROVED.equals(status) ? "permission_approved" : "permission_rejected";
   623→            String documentName = "";
   624→            try {
   625→                SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(request.getDocumentId());
   626→                documentName = node != null ? node.getName() : "";
   627→            } catch (Exception e) {
   628→                log.debug("[1822-PermApply] notifyApplicantResult get node name failed documentId={}", request.getDocumentId());
   629→            }
   630→
   631→            Map<String, Object> extras = new HashMap<>();
   632→            extras.put("requestId", request.getId());
   633→            extras.put("documentId", request.getDocumentId());
   634→            extras.put("documentName", documentName);
   635→            extras.put("status", status);
   636→            extras.put("approverUserId", String.valueOf(approverUserId));
   637→            extras.put("approverNickName", approverNickName != null ? approverNickName : "");
   638→
   639→            Map<String, Object> bodyMap = new HashMap<>();
   640→            bodyMap.put(BODY_EXTRAS, extras);
   641→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
   642→
   643→            apitableGrpcClientService.createNotification(
   644→                templateId,
   645→                String.valueOf(approverUserId),
   646→                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
   647→                request.getDocumentId(),
   648→                request.getSpaceId(),
   649→                bodyJson,
   650→                false
   651→            );
   652→            log.info("[1822-PermApply] notifyApplicantResult requestId={} status={} applicantUserId={}",
   653→                request.getId(), status, request.getApplicantUserId());
   654→        } catch (Exception e) {
   655→            log.error("[1822-PermApply] ERROR notifyApplicantResult requestId={} status={} error={}",
   656→                request.getId(), status, e.getMessage(), e);
