    List<TypeCountDto> countCreatedNodesGroupByType(@Param("startAt") LocalDateTime startAt,
                                                    @Param("endAt") LocalDateTime endAt);

    @Update({
            "<script>",
            "UPDATE ${tablePrefix}space_node",
            "SET icon=#{icon}",
            "WHERE id = #{id}",
            "</script>"
    })
    void updateNodeIcon(@Param("id") Long id, @Param("icon")String icon);



}

