package com.yottastudios.ns.collabspace.control.entity;

import com.baomidou.mybatisplus.annotation.IdType;
import com.baomidou.mybatisplus.annotation.TableField;
import com.baomidou.mybatisplus.annotation.TableId;
import com.baomidou.mybatisplus.annotation.TableLogic;
import com.baomidou.mybatisplus.annotation.TableName;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.time.LocalDateTime;

/**
 * Document permission request entity.
 * 表名: collabspace_permission_request
 */
@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@TableName(keepGlobalPrefix = true, value = "permission_request")
public class PermissionRequestEntity {

    @TableId(value = "id", type = IdType.INPUT)
    private String id;

    private Long applicantUserId;

    private String documentId;

    private String spaceId;

    @TableField("requested_permission_type")
    private String requestedPermissionType;

    private String status;

    @TableField("approver_user_id")
    private Long approverUserId;

    private LocalDateTime createdAt;

    private LocalDateTime updatedAt;

    @TableLogic
    @TableField("is_deleted")
    private Integer isDeleted;
}

package com.yottastudios.ns.collabspace.control.enums;

import com.yottastudios.ns.collabspace.core.exception.BaseException;
import lombok.AllArgsConstructor;
import lombok.Getter;

/**
 * Permission request exception.
 * 错误码与 APITable 保持一致：
 * - NotificationException (1201-1299): 通知相关
 * - PermissionException (600-699): 权限相关
 * - SpacePermissionException (601-603): 空间权限相关
 */
@Getter
@AllArgsConstructor
public enum PermissionRequestException implements BaseException {

    // NotificationException (1201-1299) - 与 APITable NotificationException 保持一致
    USER_EMPTY_ERROR(1201, "user does not exist"),

    MEMBER_EMPTY_ERROR(1202, "member does not exist"),

    TMPL_TO_TAG_ERROR(1203, "template sending tag error"),

    MEMBER_MENTIONED_ERROR(1204, "member mention error"),

    PERMISSION_REQUEST_NOT_FOUND(1205, "Permission request not found"),

    NOTIFICATION_NOT_VALID(1206, "Notification not found or not a valid permission request"),

    REQUEST_ALREADY_PROCESSED(1207, "Request already processed"),

    ALREADY_HAVE_PERMISSION(1208, "Already have document permission"),

    ALREADY_SUBMITTED_REQUEST(1209, "Already submitted request"),

    APPLICANT_UNIT_NOT_FOUND(1210, "Applicant unit not found"),

    // PermissionException (600-699) - 与 APITable PermissionException 保持一致
    NODE_NOT_EXIST(600, "node does not exist"),

    NODE_ACCESS_DENIED(601, "unable to access node"),

    NODE_OPERATION_DENIED(602, "Unable to operate node"),

    SET_MAIN_ADMIN_FAIL(603, "Failed to set main admin"),

    MEMBER_NOT_IN_SPACE(604, "The member is not in the current space"),

    // SpacePermissionException - 与 APITable SpacePermissionException 保持一致
    INSUFFICIENT_PERMISSIONS(603, "Insufficient space management rights"),

    // 本地扩展错误码 (1290-1299)
    INSERT_ERROR(1290, "创建权限申请记录失败");

    private final Integer code;

    private final String message;
}

