 */
public interface PermissionRequestMapper extends BaseMapper<PermissionRequestEntity> {

    /**
     * Find pending request by document and applicant.
     */
    PermissionRequestEntity selectPendingByDocumentAndApplicant(
        @Param("documentId") String documentId,
        @Param("applicantUserId") Long applicantUserId);

    /**
     * Find by applicant user id with pagination.
     */
    List<PermissionRequestEntity> selectByApplicantUserId(
        @Param("applicantUserId") Long applicantUserId,
        @Param("status") String status,
        @Param("offset") int offset,
        @Param("limit") int limit);

    /**
     * Count by applicant user id.
     */
    int countByApplicantUserId(
        @Param("applicantUserId") Long applicantUserId,
        @Param("status") String status);

    /**
     * Update status and approver by id.
     */
    int updateStatusById(
        @Param("id") String id,
        @Param("status") String status,
        @Param("approverUserId") Long approverUserId);
}

