     1→package com.yottastudios.ns.collabspace.control.controller;
     2→
     3→import com.yottastudios.ns.collabspace.control.service.IPermissionRequestService;
     4→import com.yottastudios.ns.collabspace.core.exception.BusinessException;
     5→import com.yottastudios.ns.collabspace.core.support.ResponseData;
     6→import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
     7→import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
     8→import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
     9→import com.yottastudios.ns.collabspace.shared.context.SessionContext;
    10→import io.swagger.v3.oas.annotations.Operation;
    11→import io.swagger.v3.oas.annotations.tags.Tag;
    12→import jakarta.annotation.Resource;
    13→import lombok.extern.slf4j.Slf4j;
