    16→
    17→import java.util.Map;
    18→
    19→/**
    20→ * Notification approval controller.
    21→ * Handles permission request approval actions: approve, reject, ignore, reapprove.
    22→ * All four require validating against collabspace permission_request table (migrated from apitable).
    23→ * notificationId is the apitable player_notification.id.
    24→ * This controller resolves requestId via gRPC call to apitable before delegating to service.
    25→ */
    26→@Slf4j
    27→@RestController
    28→@Tag(name = "Notification Approval")
    29→@ApiResource(path = "/player/notification")
    30→public class NotificationApprovalController {
    31→
    32→    private static final String DOCUMENT_PERMISSION_REQUEST = "document_permission_request";
    33→
    34→    @Resource
    35→    private IPermissionRequestService permissionRequestService;
    36→
    37→    @Resource
    38→    private IApitableGrpcClientService apitableGrpcClientService;
    39→
    40→    /**
    41→     * Approve a permission request.
    42→     */
    43→    @PostResource(path = "/{notificationId}/approve", requiredPermission = false)
    44→    @Operation(summary = "Approve permission request")
    45→    public ResponseData<Void> approve(@PathVariable("notificationId") Long notificationId) {
    46→        Long userId = SessionContext.getUserId();
    47→        log.info("[1822-Approval] APPROVE entry notificationId={} approverUserId={}", notificationId, userId);
    48→        String requestId = resolveRequestId(notificationId, userId);
    49→        permissionRequestService.approveByRequestId(requestId, notificationId, userId);
    50→        return ResponseData.success();
    51→    }
    52→
    53→    /**
