@Override
public List<Long> getAdminUsersWithWorkBenchManagePermission(String spaceId) {
    SpaceEntity spaceEntity = spaceService.listByIds(new ArrayList<>(List.of(spaceId)), true).stream().
            findFirst().orElse(null);
    if (spaceEntity == null) return List.of();

    List<SpaceUserResourceRelEntity> spaceUserResourceRelEntities = spaceUserResourceRelService
            .getByResourceCodeAndSpaceId(SpaceResourceEnum.MANAGE_WORKBENCH.getValue(), spaceId);

    Set<Long> adminIds = spaceUserResourceRelEntities.stream()
            .map(SpaceUserResourceRelEntity::getUserId).
            collect(Collectors.toSet());
    adminIds.add(spaceEntity.getOwner());

    return new ArrayList<>(adminIds);
}

@Override
public boolean isUserSpaceAdmin(Long userId, String spaceId) {
    List<Long> admins = getAdminUsersWithWorkBenchManagePermission(spaceId);
    return admins.contains(userId);
}

@Override
public boolean isUserInSpace(Long userId, String spaceId) {
    // todo 性能还可以优化
    List<ApitableSpaceVo> apitableSpaceVos = apitableGrpcClientService.listSpaces(userId);
    if (CollectionUtils.isEmpty(apitableSpaceVos)) return false;
    List<String> apiSpaceIds = apitableSpaceVos.stream().map(ApitableSpaceVo::getSpaceId).toList();
    return apiSpaceIds.contains(spaceId);
}

@Override
public boolean verifyAuth(Long userId, String spaceId) {
    return isUserSpaceAdmin(userId, spaceId) || superManagerCacheService.checkSuperManager(userId);
}

