    public static void setJwtToCookie(HttpServletResponse response, Long userId) {
        String jwtToken = generateToken(String.valueOf(userId));
        List<String> domains = getCookieDomains();

        for (String domain : domains) {
            Cookie cookie = new Cookie(getJwtCookieName(), jwtToken);
            cookie.setHttpOnly(true);
            cookie.setDomain(domain.trim());
            cookie.setPath("/");
            cookie.setMaxAge(getCookieMaxAge());
            response.addCookie(cookie);
        }
    }

