   372→    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
   373→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
   374→
   375→        String approverNickName = getApproverNickName(approverUserId);
   376→
   377→        // Get applicant unitId
   378→        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
   379→                List.of(request.getApplicantUserId()), request.getSpaceId())
   380→            .stream().findFirst().orElse(null);
   381→        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   382→        Long unitId = applicantMember.getUnitId();
   383→        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   384→
   385→        // Map permission type to node role
   386→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
   387→        log.info("[1822-PermApply] APPROVE mapRole requestId={} requestedType={} nodeRole={} unitId={} documentId={}",
   388→            request.getId(), request.getRequestedPermissionType(), nodeRole, unitId, request.getDocumentId());
   389→
   390→        // Add node role
   391→        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
   392→        if (spaceNodeId != null) {
   393→            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
   394→                Collections.singletonList(unitId));
   395→            log.info("[1822-PermApply] APPROVE addNodeRole ok spaceNodeId={} nodeRole={} unitId={}", spaceNodeId, nodeRole, unitId);
   396→        } else {
   397→            log.warn("[1822-PermApply] APPROVE WARN spaceNodeId not found for documentId={}, node permission grant SKIPPED",
   398→                request.getDocumentId());
   399→        }
   400→
   401→        // Update permission request status in collabspace
   402→        int rows = baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
   403→        log.info("[1822-PermApply] APPROVE DB updateStatus requestId={} status=APPROVED approverUserId={} rows={}",
   404→            request.getId(), approverUserId, rows);
   405→
   406→        // Update notification extras in apitable (via gRPC) — updates shared notification record for all recipients
   407→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
   408→            String.valueOf(approverUserId), approverNickName);
   409→
   410→        // Mark approver's own notification as read
   411→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
   412→
   413→        // Mark all other admin/manager recipients' notifications as read (same shared notificationId)
   414→        markOtherRecipientNotificationsRead(notificationId, request, approverUserId);
   415→
   416→        // Notify applicant that their request was approved
   417→        notifyApplicantResultAsync(request, STATUS_APPROVED, approverUserId, approverNickName);
   418→
   419→        log.info("[1822-PermApply] APPROVE done requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
   420→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
   421→    }
