    @SneakyThrows
    @Override
    public void recordNodeBrowsing(NodeBrowsingRo req, StreamObserver<BasicResult> responseObserver) {
        Integer code = DEFAULT_SUCCESS_CODE;
        String message = DEFAULT_SUCCESS_MESSAGE;
        String spaceId = null;
        try {
            spaceId = iNodeService.getSpaceIdByNodeId(req.getNodeId());
        } catch (BusinessException e) {
            log.warn("节点不存在,nodeId:{}", req.getNodeId());
            code = DEFAULT_ERROR_CODE;
            message = DEFAULT_ERROR_MESSAGE;
        }
        // only for folder
        if (req.getNodeId().startsWith(IdRulePrefixEnum.FOD.getIdRulePrefixEnum())) {
            Long userId = iUserService.getUserIdByUuid(req.getUuid());
            Long memberId = iMemberService.getMemberIdByUserIdAndSpaceId(userId, spaceId);
            if (userId == null || memberId == null) {
                log.warn("user 或者member不存在,userId:{},spaceId:{}", req.getUuid(), spaceId);
                code = DEFAULT_ERROR_CODE;
                message = DEFAULT_ERROR_MESSAGE;
            } else {
                // 这个地方根据 req.getNodeid() 查出来nodeId, 然后去node表里查询该nodeId所对应的nodeType, 然后传进下面去
                NodeType nodeType = iNodeService.getTypeByNodeId(req.getNodeId());
                multiDatasourceAdapterTemplate.saveOrUpdateNodeVisitRecord(spaceId, memberId, req.getNodeId(), nodeType);
            }
        }
        BasicResult result = BasicResult.newBuilder()
                .setCode(code)
                .setMessage(message).
                setSuccess(true).build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

    @Override
    public void addScheduleTemplate(AddScheduleTemplateBo req, StreamObserver<BasicResult> responseObserver) {
        log.info("addScheduleTask insert record ");
        ProtocolStringList cronExpressionList = req.getCronExpressionList();
        log.info("addScheduleTask insert record cronExpressionList:{}", cronExpressionList);
        if (!CollectionUtils.isEmpty(cronExpressionList)) {
            List<ScheduleTemplateEntity> scheduleTemplateEntities = cronExpressionList.stream().map(cronExpression -> ScheduleTemplateEntity.builder()
                .templateName("机器人")
                .sourceId(req.getSourceId())
                .cornExpression(cronExpression)
                .executeMethod("GRPC#TriggerRobot")
                .isActive(1).build()
            ).collect(Collectors.toList());
            if (!CollectionUtils.isEmpty(cronExpressionList)) {
                iScheduleTemplateService.saveBySourceId(scheduleTemplateEntities, req.getSourceId());
            }
        }
        BasicResult result = BasicResult.newBuilder()
                .setCode(DEFAULT_SUCCESS_CODE)
                .setMessage(DEFAULT_SUCCESS_MESSAGE).
                setSuccess(true).build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

    @Override
    public void addTimeDelayRobot(AddTimeDelayRobotBo req, StreamObserver<BasicResult> responseObserver) {
        List<DelayItem> delayFilterList = req.getDelayFilterList();
        String robotId = req.getRobotId();
        String triggerId = req.getTriggerId();
        String timeFieldId = req.getTimeFieldId();
        if (!CollectionUtils.isEmpty(delayFilterList)) {
            List<DelayFilterItem> delayFilter = new ArrayList<>();
            for (DelayItem item : delayFilterList){
                delayFilter.add(DelayFilterItem.builder()
                        .type(item.getType())
                        .value(item.getValue())
                        .time(item.getTime()).build());
            }
            TimeDelayRobotDto addTimeDelayRobotDto = TimeDelayRobotDto.builder()
                    .robotId(robotId)
                    .triggerId(triggerId)
                    .timeFieldId(timeFieldId)
                    .delayFilter(delayFilter).build();
            iTimeDelayRobotService.addTimeDelayRobot(addTimeDelayRobotDto);
        }
        BasicResult result = BasicResult.newBuilder()
            .setCode(DEFAULT_SUCCESS_CODE)
            .setMessage(DEFAULT_SUCCESS_MESSAGE).
            setSuccess(true).build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

