    @Override
    public void createNode(CreateNodeRo request, StreamObserver<CreateNodeResult> responseObserver) {
        Long userId = request.getUserId();
        String spaceId = request.getSpaceId();
        String name = request.getName();
        Integer type = request.getType();
        NodeRelRequest nodeRelRequest = request.getExtra();
        String rootNodeId = iNodeService.getRootNodeIdBySpaceId(spaceId);
        NodeOpRo nodeOpRo = NodeOpRo.builder()
                .nodeName(name)
                .checkDuplicateName(false)
