                    nodeRelRequest.getViewId(),nodeRelRequest.getViewName()));

        String nodeId = HolderContextUtil.execute(userId, spaceId, () -> iNodeService.createNode(userId, spaceId, nodeOpRo));

        CreateNodeResult result = CreateNodeResult.newBuilder()
                .setNodeId(nodeId)
                .build();

        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

