    @Override
    public void findUnitMemberVo(FindUnitMemberVoRequest request, StreamObserver<FindUnitMemberVoResponse> responseObserver) {
        List<Long> userIds = request.getUserIdsList();
        String spaceId = request.getSpaceId();
        // 可以优化查询,和下面的合一起
        List<MemberEntity> members = memberService.getByUserIdsAndSpaceId(userIds, spaceId);

        List<com.apitable.organization.vo.UnitMemberVo> unitMemberVoList;
        if (CollectionUtils.isEmpty(members)) {
            unitMemberVoList = List.of();
        } else {
            List<Long> memberIds = members.stream().map(MemberEntity::getId).toList();
            unitMemberVoList = organizationService.findUnitMemberVo(memberIds);
            nodeRoleService.handleNodeMemberTeamName(unitMemberVoList, spaceId);
        }

        FindUnitMemberVoResponse.Builder responseBuilder = FindUnitMemberVoResponse.newBuilder();
        for (com.apitable.organization.vo.UnitMemberVo memberVo : unitMemberVoList) {

            List<MemberTeamPathInfo> teamDataList =
                    memberVo.getTeamData() != null
                            ? memberVo.getTeamData().stream().map(this::convertToGrpcMemberTeamPathInfo).toList()
                            : List.of();

            UnitMemberVo.Builder unitMemberBuilder = UnitMemberVo.newBuilder()
                    .setUnitId(memberVo.getUnitId() != null ? memberVo.getUnitId() : 0L)
                    .setMemberId(memberVo.getMemberId() != null ? memberVo.getMemberId() : 0L)
                    .setMemberType(memberVo.getMemberType() != null ? memberVo.getMemberType() : 0)
                    .setUserId(memberVo.getUserId() != null ? memberVo.getUserId() : "")
                    .setUuid(memberVo.getUuid() != null ? memberVo.getUuid() : "")
                    .setOriginName(memberVo.getOriginName() != null ? memberVo.getOriginName() : "")
                    .setMemberName(memberVo.getMemberName() != null ? memberVo.getMemberName() : "")
                    .setEmail(memberVo.getEmail() != null ? memberVo.getEmail() : "")
                    .setMobile(memberVo.getMobile() != null ? memberVo.getMobile() : "")
                    .setAvatar(memberVo.getAvatar() != null ? memberVo.getAvatar() : "")
                    .setIsActive(memberVo.getIsActive() != null ? memberVo.getIsActive() : false)
                    .setTeams(memberVo.getTeams() != null ? memberVo.getTeams() : "")
                    .setIsAdmin(memberVo.getIsAdmin() != null ? memberVo.getIsAdmin() : false)
                    .setIsNickNameModified(memberVo.getIsNickNameModified() != null ? memberVo.getIsNickNameModified() : false)
                    .setIsMemberNameModified(memberVo.getIsMemberNameModified() != null ? memberVo.getIsMemberNameModified() : false)
                    .addAllTeamData(teamDataList)
                    .setAvatarColor(memberVo.getAvatarColor() != null ? memberVo.getAvatarColor() : 0)
                    .setNickName(memberVo.getNickName() != null ? memberVo.getNickName() : "");

            responseBuilder.addUnitMembers(unitMemberBuilder.build());
        }

        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

