    @Override
    public void addUsersToTeam(OperateUsersOfTeamRequest request, StreamObserver<BasicResult> responseObserver) {

        String spaceId = request.getSpaceId();
        Long teamId = request.getTeamId();
        boolean bindTag = request.getBindTag();
        if (teamId == 0L) {
            teamId = teamMapper.selectRootIdBySpaceId(spaceId);
        }

        List<Long> userIdsList = request.getUserIdsList();

        List<MemberEntity> memberEntities = iMemberService.selectByUserIdsAndSpaceIdIgnoreDelete(userIdsList, spaceId);
        //先处理use入space
        List<Long> memberIds=new ArrayList<>();
        List<Long> addUserIds;
        if(CollectionUtils.isNotEmpty(memberEntities)){

            //add

            List<Long> currentUserId = memberEntities.stream().map(MemberEntity::getUserId).toList();
            addUserIds=new ArrayList<>(userIdsList.stream().filter(x->!currentUserId.contains(x)).toList());

            List<MemberEntity> validMember = memberEntities.stream().filter(x->!x.getIsDeleted()).toList();
            if(CollectionUtils.isNotEmpty(validMember)){
                List<Long> currentMemberId = validMember.stream().map(MemberEntity::getId).toList();
                memberIds.addAll(currentMemberId);
            }

            //restore
            List<MemberEntity> deleteMember = memberEntities.stream().filter(MemberEntity::getIsDeleted).toList();
            if(CollectionUtils.isNotEmpty(deleteMember)){
                Map<Long,Long> restoreMemberMap = deleteMember.stream().collect(Collectors.toMap(MemberEntity::getUserId,MemberEntity::getId));
                List<Long> restoreUserIds = new ArrayList<>(restoreMemberMap.keySet().stream().toList());
                List<UserEntity> restoreUsers = iUserService.selectByIds(restoreUserIds);
                if(CollectionUtils.isNotEmpty(restoreUsers)){
                    Map<Long, UserEntity> userMap = restoreUsers.stream().collect(Collectors.toMap(UserEntity::getId, Function.identity(),(v1,v2)->v1));
                    Map<Long, UserEntity> userMemberInfoMap=new HashMap<>();
                    for (Map.Entry<Long, Long> entry : restoreMemberMap.entrySet()) {
                        Long k = entry.getKey();
                        Long v = entry.getValue();
                        UserEntity userEntity = userMap.get(k);
                        if (null != userEntity) {
                            userMemberInfoMap.put(v, userEntity);
                            memberIds.add(v);
                        }
                    }
                    iMemberService.restoreMemberBatchNoTeam(userMemberInfoMap,spaceId);
                }
                if(CollectionUtils.isNotEmpty(addUserIds)&&CollectionUtils.isNotEmpty(restoreUserIds))
                    addUserIds.removeAll(restoreUserIds);
            }

        }else{
            addUserIds=userIdsList;
        }

        if(CollectionUtils.isNotEmpty(addUserIds)){
            addUserIds=addUserIds.stream().distinct().toList();
            List<UserEntity> userEntities = iUserService.selectByIds(addUserIds);
            if(CollectionUtils.isNotEmpty(userEntities)){
                List<Long> addMemberIds = iMemberService.createMemberBatchNoTeam(userEntities, spaceId);
                memberIds.addAll(addMemberIds);
            }
        }

        memberIds=memberIds.stream().distinct().toList();
        TeamAddMemberRo teamAddMemberRo = new TeamAddMemberRo();
        List<OrgUnitRo> unitList = new ArrayList<>();
        memberIds.forEach(m->{
            OrgUnitRo orgUnitRo = new OrgUnitRo();
            orgUnitRo.setId(m);
            orgUnitRo.setType(2);
            unitList.add(orgUnitRo);
        });
        teamAddMemberRo.setTeamId(teamId);
        teamAddMemberRo.setUnitList(unitList);
        iMemberService.addTeamMemberByBind(spaceId,teamAddMemberRo,bindTag?1:0);


        BasicResult result = BasicResult.newBuilder()
                .setCode(DEFAULT_SUCCESS_CODE)
                .setMessage(DEFAULT_SUCCESS_MESSAGE).
                setSuccess(true).build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();

    }

