    @Override
    public void deleteTeamByTeamId(DeleteTeamByTeamIdRequest ro,StreamObserver<BasicResult> responseObserver) {

        long teamId = ro.getTeamId();
        boolean aioBind = ro.getAioBind();

        TeamEntity department = teamService.getById(teamId);
        if(null==department){
            BasicResult result = BasicResult.newBuilder()
                    .setCode(DEFAULT_ERROR_CODE)
                    .setMessage("team does not exist").
                    setSuccess(true).build();
            responseObserver.onNext(result);
        }else{
            // 是否继续执行删除小组成员的逻辑
            boolean isContinue = true;
            // 获取根路径组
            String spaceId = department.getSpaceId();
            TeamEntity rootTeam = teamMapper.selectAllBySpaceId(spaceId).stream().filter(team -> team.getParentId() == 0)
                    .findFirst().orElse(null);
            if (rootTeam == null){
                BasicResult result = BasicResult.newBuilder()
                        .setCode(DEFAULT_ERROR_CODE)
                        .setMessage("has no root team").
                        setSuccess(true).build();
                responseObserver.onNext(result);
                isContinue = false;
            }
            int retCount = SqlTool.retCount(teamMapper.existChildrenByParentId(teamId));
            if (retCount != 0 && isContinue) {
                // 获取子集小组
                List<TeamEntity> subTeamList = teamMapper.selectChildrenByParentId(teamId);

                // 子小组换绑到根路径小组
                subTeamList.forEach(team -> {
                    team.setParentId(rootTeam.getId());
                    team.setUpdatedAt(LocalDateTime.now());
                    teamMapper.updateById(team);
                });

            }
            if (isContinue){
                List<Long> memberList = teamMemberRelMapper.selectMemberIdsByTeamIds(List.of(teamId));;
                if(!memberList.isEmpty()){
                    // 逻辑更改，加入有人，把人移除组，把人移入根路径组，加入有子级小组需要重新绑定到根路径组
                    // 获取根路径小组成员
                    List<Long> rootIdList = teamMemberRelMapper.selectMemberIdsByTeamIds(List.of(rootTeam.getId()));
                    // 获取需要添加的成员
                    List<Long> needAddUserList = memberList.stream().filter(o -> !rootIdList.contains(o)).toList();
                    if (!needAddUserList.isEmpty() && !aioBind){
                        // 更改到根路径小组
                        teamMemberRelService.addMemberTeams(needAddUserList, List.of(rootTeam.getId()));
                    }

                    // 删除全部小组成员
                    teamMemberRelService.removeByTeamIds(List.of(teamId));
                    if(!needAddUserList.isEmpty() && aioBind){
                        // 绑定小组，判断当前用户是否在其他组内，假如不在，把这个成员在空间站内移除
                        List<Long> allUserIds =  teamService.getMemberIdsByTeamIds(List.of(rootTeam.getId()));
                        List<Long> needRemoveSpaceUserIds = needAddUserList.stream().filter(o -> !allUserIds.contains(o)).toList();
                        needRemoveSpaceUserIds.forEach(memberId -> {
                            iMemberService.batchDeleteMemberFromSpace(spaceId,
                                    Collections.singletonList(memberId), true);
                        });

                    }
                    // 删除小组
                    teamService.deleteTeam(teamId);
                    BasicResult result = BasicResult.newBuilder()
                            .setCode(DEFAULT_SUCCESS_CODE)
                            .setMessage(DEFAULT_SUCCESS_MESSAGE).
                            setSuccess(true).build();
                    responseObserver.onNext(result);
                }else{
                    teamService.deleteTeam(teamId);
                    if(aioBind)
                        teamMemberRelService.removeByTeamIds(List.of(teamId));

                    BasicResult result = BasicResult.newBuilder()
                            .setCode(DEFAULT_SUCCESS_CODE)
                            .setMessage(DEFAULT_SUCCESS_MESSAGE).
                            setSuccess(true).build();
                    responseObserver.onNext(result);
                }
            }
        }


        responseObserver.onCompleted();
    }

