    @Override
    public void addSpaceSubAdmin(AddSpaceSubAdminRequest request, StreamObserver<BasicResult> responseObserver) {
        String spaceId = request.getSpaceId();
        List<Long> userIdsList = request.getUserIdsList();
        List<String> resourceCodesOrigin = request.getResourceCodesList();
        List<String> resourceCodes = spaceResourceMapper.selectResourceCodesByGroupCode(CollUtil.distinct(resourceCodesOrigin));

        Integer code = DEFAULT_SUCCESS_CODE;
        String message = DEFAULT_SUCCESS_MESSAGE;

        try {
            List<MemberEntity> memberEntities = iMemberService.selectByUserIdsAndSpaceIdIgnoreDelete(userIdsList, spaceId);
            List<Long> memberIds = new ArrayList<>();
            List<Long> addUserIds = new ArrayList<>();

            if (CollectionUtils.isNotEmpty(memberEntities)) {
                List<MemberEntity> validMembers = memberEntities.stream().filter(x -> !x.getIsDeleted()).toList();
                if (CollectionUtils.isNotEmpty(validMembers)) {
                    List<Long> currentUserIds = validMembers.stream().map(MemberEntity::getUserId).toList();
                    addUserIds = userIdsList.stream().filter(x -> !currentUserIds.contains(x)).toList();
                    List<Long> currentMemberIds = validMembers.stream().map(MemberEntity::getId).toList();
                    memberIds.addAll(currentMemberIds);
                }

                List<MemberEntity> deletedMembers = memberEntities.stream().filter(MemberEntity::getIsDeleted).toList();
                if (CollectionUtils.isNotEmpty(deletedMembers)) {
                    Map<Long, Long> restoreMemberMap = deletedMembers.stream()
                            .collect(Collectors.toMap(MemberEntity::getUserId, MemberEntity::getId));
                    List<Long> restoreUserIds = restoreMemberMap.keySet().stream().toList();
                    List<UserEntity> restoreUsers = iUserService.selectByIds(restoreUserIds);

                    if (CollectionUtils.isNotEmpty(restoreUsers)) {
                        Map<Long, UserEntity> userMap = restoreUsers.stream()
                                .collect(Collectors.toMap(UserEntity::getId, Function.identity()));
                        Map<Long, UserEntity> userMemberInfoMap = new HashMap<>();

                        for (Map.Entry<Long, Long> entry : restoreMemberMap.entrySet()) {
                            Long userId = entry.getKey();
                            Long memberId = entry.getValue();
                            UserEntity userEntity = userMap.get(userId);
                            if (userEntity != null) {
                                userMemberInfoMap.put(memberId, userEntity);
                                memberIds.add(memberId);
                            }
                        }
                        iMemberService.restoreMemberBatchNoTeam(userMemberInfoMap, spaceId);
                    }
                }
            } else {
                addUserIds = userIdsList;
            }

            if (CollectionUtils.isNotEmpty(addUserIds)) {
                List<UserEntity> userEntities = iUserService.selectByIds(addUserIds);
                if (CollectionUtils.isNotEmpty(userEntities)) {
                    List<Long> newMemberIds = iMemberService.createMemberBatchNoTeam(userEntities, spaceId);
                    memberIds.addAll(newMemberIds);
                }
            }

            memberIds = memberIds.stream().distinct().toList();

            if (memberIds.isEmpty()) {
                log.warn("No valid members found for userIds: {} in spaceId: {}", userIdsList, spaceId);
                code = DEFAULT_ERROR_CODE;
                message = "No valid members found";
            } else {
                iSpaceRoleService.saveSpaceRole(spaceId, memberIds, resourceCodes);
                log.info("Successfully added space sub admin for spaceId: {}, memberIds: {}, resourceCodes: {}",
                        spaceId, memberIds, resourceCodes);
            }
        } catch (Exception e) {
            log.error("Failed to add space sub admin for spaceId: {}, userIds: {}", spaceId, userIdsList, e);
            code = DEFAULT_ERROR_CODE;
            message = "Failed to add space sub admin: " + e.getMessage();
        }

        BasicResult result = BasicResult.newBuilder()
                .setCode(code)
                .setMessage(message)
                .setSuccess(code.equals(DEFAULT_SUCCESS_CODE))
                .build();
        responseObserver.onNext(result);
        responseObserver.onCompleted();
    }

