    @Override
    public void copyNodeToSpace(com.apitable.integration.grpc.CopyNodeToSpaceRequest request, 
            StreamObserver<com.apitable.integration.grpc.CopyNodeToSpaceResult> responseObserver) {
        Long userId = request.getUserId();
        String destSpaceId = request.getDestSpaceId();
        String destParentId = request.getDestParentId();
        String sourceNodeId = request.getSourceNodeId();

