            log.info("Successfully copied node from {} to space {}, new nodeId: {}", sourceNodeId, destSpaceId, newNodeId);
        } catch (Exception e) {
            log.error("Failed to copy node {} to space {}", sourceNodeId, destSpaceId, e);
            responseObserver.onError(new RuntimeException("Failed to copy node: " + e.getMessage()));
        } finally {
            UserHolder.remove();
        }
    }

    @Override
    public void exportNodeToSpaceCopy(ExportNodeToSpaceCopyRequest request,
                                      StreamObserver<ExportNodeToSpaceCopyResult> responseObserver) {
        log.info("收到导出NodeToSpaceCopy请求，spaceId: {}, nodeIds: {}", request.getSpaceId(), request.getNodeIdsList());

        ExportNodeToSpaceCopyResult.Builder responseBuilder = ExportNodeToSpaceCopyResult.newBuilder();

        try {
            String spaceId = request.getSpaceId();
            List<String> nodeIds = request.getNodeIdsList();

            if (spaceId.trim().isEmpty()) {
                responseBuilder.setSuccess(false)
                        .setMessage("spaceId不能为空");
                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();
                return;
            }

            NodeToSpaceCopyDto nodesToCopy = iNodeShareService.getNodeToSpaceCopyInfoBySpaceId(spaceId,nodeIds);

            String jsonContent = objectMapper.writeValueAsString(nodesToCopy);
            byte[] jsonBytes = jsonContent.getBytes(StandardCharsets.UTF_8);

            String fileName = "node_to_space_copy_" + System.currentTimeMillis() + ".json";

            //导出文件到对方minio, 直接用本服务minio会因权限报错
            AssetUploadCertificateRO uploadRequest = new AssetUploadCertificateRO();
            uploadRequest.setType(AssetType.RUBBISH.getValue());
            uploadRequest.setCount(1);

            RestClient restClient = RestClient.create();
            ResponseData<List<AssetUploadCertificateVO>> uploadResponse = restClient.post()
                    .uri(privateHost +"/api/v1/asset/upload/preSignedUrl")
                    .contentType(MediaType.APPLICATION_JSON)
                    .body(uploadRequest)
                    .retrieve()
                    .body(new ParameterizedTypeReference<ResponseData<List<AssetUploadCertificateVO>>>() {});

            if (uploadResponse == null || uploadResponse.getData() == null || uploadResponse.getData().isEmpty()) {
                throw new RuntimeException("Failed to get upload certificate");
            }

            AssetUploadCertificateVO certificate = uploadResponse.getData().get(0);
            log.info("originUploadUrl: {}",certificate.getUploadUrl());
            String remoteUploadUrl = certificate.getUploadUrl().replaceFirst("^(https?://[^/]+)", privateOssHost);
            log.info("remoteUploadUrl: {}",remoteUploadUrl);

            // 使用HttpURLConnection上传到minio, restClient会报错
            HttpURLConnection uploadConnection = null;
            try {
                URL uploadUrlObj = new URL(remoteUploadUrl);
                uploadConnection = (HttpURLConnection) uploadUrlObj.openConnection();
                uploadConnection.setRequestMethod("PUT");
                uploadConnection.setDoOutput(true);
                uploadConnection.setFixedLengthStreamingMode(jsonBytes.length);
                try (OutputStream os = uploadConnection.getOutputStream()) {
                    os.write(jsonBytes);
                    os.flush();
                }
                int responseCode = uploadConnection.getResponseCode();
                if (responseCode < 200 || responseCode >= 300) {
                    try (InputStream errorStream = uploadConnection.getErrorStream()) {
                        if (errorStream != null) {
                            String errorResponse = new String(errorStream.readAllBytes(), StandardCharsets.UTF_8);
                            log.error("minio上传失败，错误详情: {}", errorResponse);
                        }
                    }
                    throw new RuntimeException("Upload to minio failed with response: " + responseCode);
                }

                log.info("minio上传成功");

            } finally {
                if (uploadConnection != null) {
                    uploadConnection.disconnect();
                }
            }

            String downloadUrl = privateOssHost +"/assets/" + certificate.getToken();

            responseBuilder.setSuccess(true)
                    .setDownloadUrl(downloadUrl)
                    .setFileName(fileName)
                    .setMessage("导出成功");

            log.info("NodeToSpaceCopy导出成功，spaceId: {}, downloadUrl: {}", spaceId, downloadUrl);

        } catch (Exception e) {
            log.error("导出NodeToSpaceCopy失败", e);
            responseBuilder.setSuccess(false)
                    .setMessage("导出失败: " + e.getMessage());
        }

        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

    @Override
    public void importNodeToSpaceCopy(ImportNodeToSpaceCopyRequest request, StreamObserver<BasicResult> responseObserver) {
        log.info("收到导入NodeToSpaceCopy请求，downloadUrl: {}, migrateHost: {}", request.getDownloadUrl(), request.getMigrateHost());

        Integer code = DEFAULT_SUCCESS_CODE;
        String message = DEFAULT_SUCCESS_MESSAGE;

