                    memberMapper.selectSpaceMembers(page, request.getSpaceId());

            // 填充teamName
            List<Long> memberIdList = pageResult.getRecords().stream().map(SpaceMembersDTO::getMemberId).toList();
            List<com.apitable.space.dto.TeamMemberDTO> teamMemberDTOs =
                    teamMapper.selectTeamByMembers(memberIdList, request.getSpaceId());
            Map<Long, List<Long>> memberTeamMap = teamMemberDTOs.stream()
                    .collect(Collectors.groupingBy(
                            com.apitable.space.dto.TeamMemberDTO::getMemberId,
                            Collectors.mapping(com.apitable.space.dto.TeamMemberDTO::getTeamId, Collectors.toList())
                    ));

            pageResult.getRecords().forEach(teamMemberDTO -> {
                com.apitable.space.dto.TeamMemberDTO memberDTO = teamMemberDTOs.stream().
                        filter(o -> o.getMemberId().equals(teamMemberDTO.getMemberId())).findFirst().orElse(null);
                if (memberDTO != null) {
                    teamMemberDTO.setTeamName(memberDTO.getTeamName());
                }
            });

            responseBuilder.setSuccess(true)
                            .setTotalCount((int)pageResult.getTotal());
            List<GetSpaceMemberResult> memberResultList = new ArrayList<>();
            pageResult.getRecords().forEach(memberResult -> {
                GetSpaceMemberResult  getSpaceMemberResult = GetSpaceMemberResult.newBuilder().setEmail(memberResult.getEmail() != null ? memberResult.getEmail() : "")
                        .setSpaceId(request.getSpaceId())
                        .setMemberId(memberResult.getMemberId().toString())
                        .setMemberName(memberResult.getMemberName())
                        .setIsPrimary(memberResult.getIsPrimary())
                        .setIsSubAdmin(memberResult.getIsSubAdmin())
                        .setTeamName(memberResult.getTeamName())
                        .addAllTeamIdList(!memberTeamMap.containsKey(memberResult.getMemberId())?
                                new ArrayList<>():memberTeamMap.get(memberResult.getMemberId())).build();
                memberResultList.add(getSpaceMemberResult);
            });
            responseBuilder.addAllMembers(memberResultList);
        }
        catch (BusinessException e){
            log.error("通知失败：", e);
            responseBuilder.setSuccess(false);
        }
        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

