    /**
     * 通用创建通知，供 collabspace 调用.
     * 透传给 PlayerNotificationService.createNotify
     */
    @Override
    public void createNotification(CreateNotificationRequest request,
                                   StreamObserver<CreateNotificationResponse> responseObserver) {
        log.info("[collabspace-notify] createNotification templateId={} fromUser={} toUsers={} nodeId={}",
                request.getTemplateId(), request.getFromUserId(), request.getToUserIdsList(), request.getNodeId());
        CreateNotificationResponse.Builder responseBuilder = CreateNotificationResponse.newBuilder();
        try {
            NotificationCreateRo ro = new NotificationCreateRo();
            ro.setTemplateId(request.getTemplateId());
            ro.setFromUserId(request.getFromUserId());
            ro.setToUserId(request.getToUserIdsList());
            ro.setNodeId(request.getNodeId());
            ro.setSpaceId(request.getSpaceId());
            if (!request.getNotifyBody().isEmpty()) {
                ro.setBody(cn.hutool.json.JSONUtil.parseObj(request.getNotifyBody()));
            }
            ro.setSendKnockNotification(request.getSendKnockNotification());

            playerNotificationService.createNotify(ro);

            // 取第一条通知的 ID 返回（用于审批关联）
            // createNotify 内部会 insert，故通过查询获取
            // 由于 createNotify 不返回 ID，这里简单返回 0，让调用方不依赖此 ID
            responseBuilder.setSuccess(true)
                    .setMessage("notification created")
                    .setFirstNotificationId(0L);
        } catch (BusinessException e) {
            log.error("[collabspace-notify] createNotification failed: {}", e.getMessage(), e);
            responseBuilder.setSuccess(false).setMessage(e.getMessage());
        } catch (Exception e) {
            log.error("[collabspace-notify] createNotification error: {}", e.getMessage(), e);
            responseBuilder.setSuccess(false).setMessage("internal error");
        }
        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

    /**
     * 更新通知 body extras（审批后写入 status、approver 信息）.
     */
    @Override
    public void updateNotificationExtras(UpdateNotificationExtrasRequest request,
                                         StreamObserver<com.apitable.integration.grpc.BasicResult> responseObserver) {
        log.info("[collabspace-notify] updateNotificationExtras notificationId={} status={}",
                request.getNotificationId(), request.getStatus());
        try {
            cn.hutool.json.JSONObject bodyJson = new cn.hutool.json.JSONObject();
            cn.hutool.json.JSONObject extras = new cn.hutool.json.JSONObject();
            extras.set("status", request.getStatus());
            extras.set("approverUserId", request.getApproverUserId());
            extras.set("approverNickName", request.getApproverNickName());
            bodyJson.set("extras", extras);

            playerNotificationMapper.updateNotifyBodyById(request.getNotificationId(), bodyJson.toString());

            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(0).build());
        } catch (Exception e) {
            log.error("[collabspace-notify] updateNotificationExtras failed notificationId={} error={}",
                    request.getNotificationId(), e.getMessage(), e);
            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(-1).setMessage(e.getMessage()).build());
        }
        responseObserver.onCompleted();
    }

    /**
     * 查询通知 body extras（审批时通过 notificationId 反查 requestId）.
     */
    @Override
    public void getNotificationExtras(GetNotificationExtrasRequest request,
                                      StreamObserver<GetNotificationExtrasResponse> responseObserver) {
        log.info("[collabspace-notify] getNotificationExtras notificationId={} toUser={}",
                request.getNotificationId(), request.getToUserId());
        GetNotificationExtrasResponse.Builder responseBuilder = GetNotificationExtrasResponse.newBuilder();
        try {
            PlayerNotificationEntity notification = playerNotificationMapper.selectById(request.getNotificationId());
            if (notification == null) {
                responseBuilder.setSuccess(false).setMessage("notification not found");
                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();
                return;
            }
            if (request.getToUserId() != notification.getToUser()) {
                responseBuilder.setSuccess(false).setMessage("toUser mismatch");
                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();
                return;
            }
            responseBuilder.setSuccess(true);
            responseBuilder.setTemplateId(notification.getTemplateId() != null ? notification.getTemplateId() : "");
            if (notification.getNotifyBody() != null && !notification.getNotifyBody().isEmpty()) {
                cn.hutool.json.JSONObject body = cn.hutool.json.JSONUtil.parseObj(notification.getNotifyBody());
                cn.hutool.json.JSONObject extras = body.getJSONObject("extras");
                if (extras != null) {
                    responseBuilder.setRequestId(extras.getStr("requestId") != null ? extras.getStr("requestId") : "");
                    responseBuilder.setSpaceId(extras.getStr("spaceId") != null ? extras.getStr("spaceId") : "");
                }
            }
            responseBuilder.setMessage("ok");
        } catch (Exception e) {
            log.error("[collabspace-notify] getNotificationExtras failed notificationId={} error={}",
                    request.getNotificationId(), e.getMessage(), e);
            responseBuilder.setSuccess(false).setMessage(e.getMessage());
        }
        responseObserver.onNext(responseBuilder.build());
        responseObserver.onCompleted();
    }

    /**
     * 标记通知已读/未读.
     */
    @Override
    public void setNotificationRead(SetNotificationReadRequest request,
                                    StreamObserver<com.apitable.integration.grpc.BasicResult> responseObserver) {
        log.info("[collabspace-notify] setNotificationRead notificationId={} toUser={} isRead={}",
                request.getNotificationId(), request.getToUserId(), request.getIsRead());
        try {
            if (request.getIsRead()) {
                playerNotificationMapper.updateReadIsTrueByIds(new String[]{String.valueOf(request.getNotificationId())});
            } else {
                playerNotificationMapper.updateReadIsFalseByIdAndToUser(
                        request.getNotificationId(), request.getToUserId());
            }
            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(0).build());
        } catch (Exception e) {
            log.error("[collabspace-notify] setNotificationRead failed notificationId={} error={}",
                    request.getNotificationId(), e.getMessage(), e);
            responseObserver.onNext(com.apitable.integration.grpc.BasicResult.newBuilder()
                    .setCode(-1).setMessage(e.getMessage()).build());
        }
        responseObserver.onCompleted();
    }

